interviewQuestions.answer:
Partial application means pre-filling some of a function's arguments using bind(): <code>function add(a, b) { return a + b; }
const add5 = add.bind(null, 5);
console.log(add5(3)); // 8
console.log(add5(10)); // 15</code> The first argument (a) is permanently set to 5.

codeExamples.code:
const user = {
  name: 'Alice',
  greet() { console.log(`Hello, ${this.name}`); }
};

const unboundedGreet = user.greet;
unboundedGreet(); // 'Hello, undefined' (wrong this)

const boundedGreet = user.greet.bind(user);
boundedGreet(); // 'Hello, Alice' (correct)

// Even when passed to setTimeout:
setTimeout(user.greet.bind(user), 100); // 'Hello, Alice'

function multiply(a, b, c) {
  return a * b * c;
}

// Pre-fill the first argument
const double = multiply.bind(null, 2);
console.log(double(3, 4)); // 24 (2 * 3 * 4)

// Pre-fill first two arguments
const tripleByFour = multiply.bind(null, 3, 4);
console.log(tripleByFour(5)); // 60 (3 * 4 * 5)

// Practical: tax calculator
const addTax = (rate, price) => price + (price * rate / 100);
const addSalesTax = addTax.bind(null, 8); // 8% tax
console.log(addSalesTax(100)); // 108
console.log(addSalesTax(200)); // 216

class Button {
  constructor(label) {
    this.label = label;
    this.count = 0;

    // Without bind: 'this' would be the DOM element
    const el = document.createElement('button');
    el.textContent = label;
    el.addEventListener('click', this.handleClick.bind(this));
    document.body.appendChild(el);
  }

  handleClick() {
    this.count++;
    console.log(`${this.label} clicked ${this.count} times`);
  }
}

// Arrow function alternative:
// el.addEventListener('click', (e) => this.handleClick(e));

const obj1 = { x: 1 };
const obj2 = { x: 2 };

function getX() { return this.x; }

const bound = getX.bind(obj1);
console.log(bound());        // 1

// These all still return 1:
console.log(bound.call(obj2));   // 1 (obj2 ignored)
console.log(bound.apply(obj2));  // 1 (obj2 ignored)
console.log(bound.bind(obj2)()); // 1 (ignored)

// Even Function.prototype.call on the bound function:
// bound.call(obj2) is equivalent to:
// (function() { return getX.apply(obj1, arguments); }).call(obj2)
// The inner getX still uses obj1 as 'this'!

class Logger {
  constructor(prefix) {
    this.prefix = prefix;
    this.logCount = 0;
  }

  start() {
    // Without bind: 'this' is the timeout global
    setInterval(function() {
      this.logCount++;
      console.log(`${this.prefix}: ${this.logCount}`);
    }.bind(this), 1000);

    // Alternative with arrow function:
    // setInterval(() => {
    //   this.logCount++;
    //   console.log(`${this.prefix}: ${this.logCount}`);
    // }, 1000);
  }
}

const logger = new Logger('LOG');
logger.start();
// LOG: 1, LOG: 2, LOG: 3...
